local LMapBase = LMapBase

local typeofGameObject = typeof(UnityEngine.GameObject)
local LDisplaySpine = LDisplaySpine
local LDisplayEffect = LDisplayEffect

function LMapBase:InitMapThemeShow(themeName)
	if string.isempty(themeName) then
		themeName = "default"
	end
	if self._curThemeName == nil then
		self._curThemeName = "default"
	end
	if self._curThemeName == themeName then return end

	self:ClearMapThemeShow()
	self._curThemeName = themeName
	local mapName = self:GetMapName()
	-- local showWndRef = GameTable.ThemeConfigRef[mapName]
	local showWndRef = nil
	if not showWndRef then return end
	
	local useShow = showWndRef.useShow
	if useShow == 0 then return end
	
	local showFileName = showWndRef.showName
	local showFileRef = GameTable[showFileName]
	if not showFileRef then return end
	
	local cfgStr = nil
	for k,themeData in pairs(showFileRef) do
		local path = themeData.path
		if path ~= "Root" then
			cfgStr = themeData[themeName]
			self:_ShowMapThemeNode(path, cfgStr)
		end 
	end
end
function LMapBase:TryChangeMapTheme()
	if not self._prepareThemeName then return false end
	
	if self._curThemeName == self._prepareThemeName and self._curThemePreview == self._prepareThemePreview then
		self._prepareThemeName = nil
		self._prepareThemePreview = nil
		return false
	end

	self:ShowMapTheme(self._prepareThemeName, self._prepareThemePreview)
	self._prepareThemeName = nil
	self._prepareThemePreview = nil
	
	return true
end 

function LMapBase:PrepareMapTheme(themeName, bPreview)
	self._prepareThemeName = themeName
	self._prepareThemePreview = bPreview
end

function LMapBase:ShowMapTheme(themeName, bPreview)
	self._curThemeName = themeName
	self._curThemePreview = bPreview
	local mapPrefabName = self:GetMapThemePrefab(themeName)
	if string.isempty(mapPrefabName) then
		mapPrefabName = self:GetMapName()
	end

	if not string.isempty(mapPrefabName) and mapPrefabName ~= self:GetMapPrefabName() then
		self:StartLoadTheme(mapPrefabName, bPreview)
	else
		self:ClearThemeMap()
		self:InitMapThemeShow(themeName)
		self:PreviewThemeMap(self:GetMapTrans(), false)
		if self._themeResRequester then
			self._themeResRequester:Dispose()
			self._themeResRequester = nil
		end
	end
end

function LMapBase:GetMapThemePrefab(themeName)
	themeName = themeName or gLGameDisplayTheme:GetMapTheme()
	local mapName = self:GetMapName()
	-- local showWndRef = GameTable.ThemeConfigRef[mapName]
	local showWndRef = nil
	if not showWndRef then return end
	
	local useShow = showWndRef.useShow
	if useShow == 0 then return end
	
	local showFileName = showWndRef.showName
	local showFileRef = GameTable[showFileName]
	if not showFileRef then return end

	local cfgStr = nil
	for k,themeData in pairs(showFileRef) do
		local path = themeData.path
		cfgStr = themeData[themeName]
		if path == "Root" then
			local itemList = string.split(cfgStr, '=')
			local mapPrefabName = itemList[2]
			return mapPrefabName
		end
	end
	return
end
function LMapBase:ClearMapThemeShow()
	if not self._curThemeName then return end

	if self._themeEffMap then
		for key,effDp in pairs(self._themeEffMap) do
			effDp:Destroy()
		end
	end
	
	if self._themeSpineMap then
		for key,spineDp in pairs(self._themeSpineMap) do
			spineDp:Destroy()
		end
	end
	
	self._themeEffMap = {}
	self._themeSpineMap = {}
end

function LMapBase:_ShowMapThemeNode(nodePath, cfgStr)
	if string.isempty(cfgStr) then return end

	local mapTrans = self:GetMapTrans()
	if CS.IsNullObject(mapTrans) then return end
	
	local nodeTrans = mapTrans:Find(nodePath)
	if CS.IsNullObject(nodeTrans) then return end
	
	local showCfgList = string.split(cfgStr, ';')
	local typeKey= nil
	local valueStr = nil
	local itemList = nil
	local typeFunc = {
		["img"] = function(key, node, value, onLoadFunc) self:_ShowMapThemeNodeImg(key, node, value, onLoadFunc) end,
		["spine"] = function(key, node, value, onLoadFunc) self:_ShowMapThemeNodeSpine(key, node, value, onLoadFunc) end,
		["eff"] = function(key, node, value, onLoadFunc) self:_ShowMapThemeNodeEff(key, node, value, onLoadFunc) end,
		["enable"] = function(key, node, value, onLoadFunc) self:_ShowMapThemeNodeEnable(key, node, value, onLoadFunc) end,
		["alpha"] = function(key, node, value, onLoadFunc) self:_ShowMapThemeNodeAlpha(key, node, value, onLoadFunc) end,
	}

	local loadCnt = 0
	local loadIdx = 0
	for idx,showCfgItem in ipairs(showCfgList) do
		itemList = string.split(showCfgItem, '=')
		typeKey = itemList[1]
		valueStr = itemList[2]
		local func = typeFunc[typeKey]
		if func then
			loadCnt = loadCnt + 1
			func(nodePath, nodeTrans, valueStr, function()
				loadIdx = loadIdx + 1
				if loadIdx >= loadCnt then
					self:_OnLoadAllNode()
				end
			end)
		end
	end
end

function LMapBase:_OnLoadAllNode()
	if self._themeSpineMap then
		local ani = nil
		for k,spine in pairs(self._themeSpineMap) do
			if spine:IsDpValid() then
				ani = spine:GetCurAnimationName()
				if not string.isempty(ani) then
					spine:ClearAnimation(0)
					spine:PlayAnimation(0, ani, true, false, 0)
				end 
			end
		end
	end
end

function LMapBase:_ShowMapThemeNodeImg(nodePath, nodeTrans, valueStr, onLoadFunc)
	if onLoadFunc then
		onLoadFunc()
	end
end

function LMapBase:_ShowMapThemeNodeSpine(nodePath, nodeTrans, valueStr, onLoadFunc)
	if string.isempty(valueStr) then return end
	if CS.IsNullObject(nodeTrans) then return end

	local valueStrlist = string.split(valueStr, "|")
	local spineName = valueStrlist[1]
	local ani = valueStrlist[2]
	local dp = LDisplaySpine:New()
	dp:CreateSpine(nodeTrans, spineName)
	dp:SetRenderOrder(0)
	dp:SetLoadedFunction(function(spine)
		if spine:IsDpValid() then
			CS.ShowObject(CS.FindTrans(spine:GetDisplayTrans(),"Collider"), false)
		end
		if not string.isempty(ani) then
			spine:PlayAnimation(0, ani, true, false, 0)
		end
		
		if onLoadFunc then
			onLoadFunc()
		end
	end)

	dp:StartLoad()
	self._themeSpineMap[nodePath] = dp
end

function LMapBase:_ShowMapThemeNodeEff(nodePath, nodeTrans, effName, onLoadFunc)
	if string.isempty(effName) then return end
	if CS.IsNullObject(nodeTrans) then return end

	local dp = LDisplayEffect:New()
	dp:CreateEffect(nodeTrans,effName)
	dp:SetLoadedFunction(function (dpEff)
		if onLoadFunc then
			onLoadFunc()
		end
	end)
	dp:StartLoadEffect()
	self._themeEffMap[nodePath] = dp
end

function LMapBase:_ShowMapThemeNodeEnable(nodePath, nodeTrans, valueStr, onLoadFunc)
	if CS.IsNullObject(nodeTrans) then return end

	local val = tonumber(valueStr) or 0
	local enable = val == 1
	CS.ShowObject(nodeTrans, enable)
	if onLoadFunc then
		onLoadFunc()
	end
end

function LMapBase:_ShowMapThemeNodeAlpha(nodePath, nodeTrans, valueStr, onLoadFunc)
	if onLoadFunc then
		onLoadFunc()
	end
end
