function LMapBase:StartLoadTheme(prefabName, bPreview)
	if string.isempty(prefabName) then return end

	self._isThemePreview = bPreview
	if self:IsThemeMapValid(prefabName) then
		if self._isThemePreview then
			self:PreviewThemeMap(self._themeMapTrans, true)
		else
			self:EnableThemeMap(self._themeMapTrans)
		end
	else
		self._themePrefabName = prefabName

		if self._themeResRequester then
			self._themeResRequester:Dispose()
			self._themeResRequester = nil
		end
		local assetPath = string.format("Map/Prefabs/%s.prefab", prefabName)
		self._themeResRequester = LxResUtil.GetAssetRequester(assetPath, typeofGameObject, function(obj)
			self:OnThemeLoaded(prefabName, obj)
		end)
		self._themeResRequester:StartRequester()
	end 
end

function LMapBase:OnThemeLoaded(prefabName, asset, assetName, bundleName)
	if self:IsDestroy() then return end

	self:ClearThemeMap()

	local parentTrans = self._parentTrans
	if not parentTrans or not CS.IsValidObject(parentTrans) then return end
	if prefabName ~= self._themePrefabName then return end
	if not asset then return end
	
	--local instGo = LxResUtil.NewObject(asset,bundleName)
	local instGo = LxResUtil.NewObject(asset)
	instGo.name = self:GetMapName()
	local instTrans = instGo.transform
	instTrans:SetParent(parentTrans, false)
	
	self._themeBundleName = bundleName
	self._themeMapName = self:GetMapName()
	
	if self._isThemePreview then
		self:PreviewThemeMap(instTrans, true)
	else
		self:EnableThemeMap(instTrans)
	end
end

function LMapBase:PreviewThemeMap(instTrans, bPreview)
	if CS.IsNullObject(instTrans) then return end

	if CS.IsValidObject(self._mapTrans) then
		CS.ShowObject(self._mapTrans, not bPreview)
	end
	if bPreview then
		self._themeMapTrans = instTrans
	end
	local buildTrans = CS.FindTrans(instTrans,"LayerRoot/BuildingLayer")
	local heroTrans = CS.FindTrans(instTrans,"LayerRoot/HeroLayer")
	if buildTrans then CS.ShowObject(buildTrans, not bPreview) end
	if heroTrans then CS.ShowObject(heroTrans, not bPreview) end
end

function LMapBase:EnableThemeMap(instTrans)
	if CS.IsNullObject(instTrans) then return end
	
	self._themeMapTrans = nil
	self._mapPrefabName = self._themePrefabName
	self:DestroyMapTrans(self._bundleName)
	self:PreviewThemeMap(instTrans, false)
	
	if self._themeBundleName then
		self._bundleName = self._themeBundleName 
		self._showMapName = self._themeMapName
	end
	self._mapTrans = instTrans

	self:InitCameraComponent()
	local mapCityTheme = gLGameDisplayTheme:GetMapTheme()
	self:InitMapThemeShow(mapCityTheme)
	self:InitMapLanguage()
	
	self:OnPrepareEnterMap()

	if not self._bVisible then self:UpdateMapVisible() end

	self:OnMapReady()	
	self:OnChangeThemeMap()
	
	LxTimer.DelayTimeCall(function()
		if not self:IsDestroy() then
			self:RegisterRedPoint()	
		end
	end, 1)
end

function LMapBase:ClearThemeMap()
	if self._themeMapTrans then
		--LxResUtil.DestroyObject(self._themeMapTrans)
		LxResUtil.DestroyObject(self._themeMapTrans.gameObject)
		self._themeMapTrans = nil
	end
	
	if CS.IsValidObject(self._mapTrans) then
		CS.ShowObject(self._mapTrans, true)
	end
end

function LMapBase:IsThemeMapValid(prefabName)
	if prefabName and prefabName == self._themePrefabName and CS.IsValidObject(self._themeMapTrans) then
		return true
	end
	return false
end

function LMapBase:OnChangeThemeMap()
	self._simuAdmireTran = nil
	if self._effCtrl then
		self._effCtrl:Destroy()
	end
	self._effCtrl = nil

	--if self._adCard then
	--	self._adCard:Destroy()
	--	self._adCard = nil
	--end

	self:DestroyDreamBubble()
	self:DestroyBuildingNpc()
	self:InitBuildingAdCard()
	self:RefreshBuildingShow()
	self:InitCameraCtrlMovePos()
	
	if self._effectTuoweiRoot then
		for _,v in ipairs(self._effectTuoweiRoot) do
			CS.ShowObject(v, true)
		end 
	end
	
	if self._effectPlayer then
		self._effectPlayer:RestartPlay()
	end


	
	self:RefreshAllBubble()

	self:SetDreamFountainSpine()

	self:OnSimulateAdmireChange()
end


